import os as _os
import sys as _sys
import io as _io
import json as _json
import re as _re
import fnmatch as _fnmatch

_MATCHER = 'Bash(git push*)'

# Cap stdin read so a malicious or buggy upstream cannot OOM the shim
# (CWE-400). Mirrors push_guard_base.MAX_STDIN_BYTES (1 MiB) with a
# small headroom; real Claude/Copilot tool_input commands are well
# below this limit. The cap belongs at the SHIM layer because the
# shim reads stdin BEFORE delegating to the wrapped script. Without
# it, the wrapped script's own cap is applied too late: the OOM has
# already happened.
_SHIM_MAX_STDIN_BYTES = 2 * 1024 * 1024


def _shim_classify(pattern):
    # MIRROR: classify_matcher (build-time, build/scripts/generate_hooks.py)
    # and _shim_classify (runtime, this inlined copy) MUST agree on the
    # grammar. Update both when the grammar changes.
    if pattern.startswith("^") and pattern.endswith("$"):
        return "regex", {"pattern": pattern}
    m = _re.match(r"^([A-Za-z_][A-Za-z0-9_]*)\((.*)\)$", pattern)
    if m:
        return "tool-glob", {"toolName": m.group(1), "argsGlob": m.group(2)}
    return "bare", {"toolName": pattern}


def _shim_normalize_args(tool_args):
    r"""Stringify and whitespace-normalize tool_input for fnmatch comparison.

    REQ-003-007: collapse \s+ to a single space and strip ends. Pattern
    is NOT normalized; authors write patterns assuming single spaces.
    """
    if isinstance(tool_args, dict):
        # Bash hooks place command under "command"; keep this fallback
        # path narrow but correct for the live corpus.
        cmd = tool_args.get("command")
        if isinstance(cmd, str):
            text = cmd
        else:
            text = _json.dumps(tool_args, sort_keys=True)
    elif isinstance(tool_args, str):
        text = tool_args
    elif tool_args is None:
        text = ""
    else:
        text = str(tool_args)
    return _re.sub(r"\s+", " ", text).strip()


def _shim_glob_match(args_glob, tool_args_norm):
    """Match args_glob against tool_args_norm with `|` as alternation.

    fnmatch treats `|` as a literal. Authors expect Claude semantics
    where each `|` branch is a separate glob alternation. Split on
    top-level `|` and OR-fold the results.
    """
    branches = args_glob.split("|") if args_glob else [""]
    for branch in branches:
        if _fnmatch.fnmatchcase(tool_args_norm, branch):
            return True
    return False


def _shim_should_fire(payload):
    kind, params = _shim_classify(_MATCHER)
    tool_name = payload.get("tool_name")
    if not isinstance(tool_name, str):
        raise ValueError("hook input missing string `tool_name` field")
    if kind == "regex":
        return _re.fullmatch(params["pattern"], tool_name) is not None
    if kind == "tool-glob":
        if tool_name != params["toolName"]:
            return False
        norm_args = _shim_normalize_args(payload.get("tool_input"))
        return _shim_glob_match(params["argsGlob"], norm_args)
    # bare
    return tool_name == params["toolName"]


def _shim_dispatch():
    try:
        _raw = _sys.stdin.buffer.read(_SHIM_MAX_STDIN_BYTES + 1)
    except Exception as exc:  # pragma: no cover - defensive
        print(
            "matcher-shim [{}]: failed to buffer stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if len(_raw) > _SHIM_MAX_STDIN_BYTES:
        print(
            "matcher-shim [{}]: stdin exceeds {} bytes; refusing".format(
                _MATCHER, _SHIM_MAX_STDIN_BYTES
            ),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        payload = _json.loads(_raw or b"{}")
    except _json.JSONDecodeError as exc:
        print(
            "matcher-shim [{}]: malformed JSON on stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        fire = _shim_should_fire(payload)
    except Exception as exc:
        print(
            "matcher-shim [{}]: dispatch error: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if _os.environ.get("COPILOT_HOOK_DEBUG"):
        kind, _ = _shim_classify(_MATCHER)
        _sys.stderr.write(
            "matcher-shim [{}]: kind={} fired={}\n".format(_MATCHER, kind, fire)
        )
    if not fire:
        _sys.exit(0)
    # Replay raw bytes into a fresh stdin so the original script reads
    # exactly what the shim inspected. Replace BEFORE calling original.
    _sys.stdin = _io.TextIOWrapper(_io.BytesIO(_raw), encoding="utf-8")
    rc = _original_main(_raw)
    if rc is None:
        rc = 0
    _sys.exit(int(rc))


# END MATCHER SHIM

def _original_main(stdin_bytes):
    # original script body begins below
    #!/usr/bin/env python3
    """Block git push when marketplace.json description counts drift.

    Thin adapter over :mod:`push_guard_base`. Activates when the changeset
    includes any file that influences plugin counts (agent templates, skill
    manifests, command definitions, marketplace.json itself) and delegates
    to ``build/scripts/validate_marketplace_counts.py``.

    Hook Type: PreToolUse
    Exit Codes (Claude Hook Semantics, exempt from ADR-035):
        0 = Allow (no manifest-affecting files, all counts current)
        2 = Block (counts stale or validator config error)
    """


    import contextlib
    import io
    import sys
    from pathlib import Path

    from _bootstrap import ensure_plugin_paths

    ensure_plugin_paths()

    from hook_utilities import get_project_directory  # noqa: E402
    from push_guard_base import run_guard  # noqa: E402

    GUARD_NAME = "manifest-count"
    # Globs cover every source directory the marketplace counter walks per
    # templates/marketplace-counters.yaml. ** matches any directory depth so
    # nested hooks (e.g., .claude/hooks/PreToolUse/...) are detected too.
    GLOBS = [
        ".claude-plugin/marketplace.json",
        ".github/plugin/marketplace.json",
        "src/claude/*.md",
        ".claude/agents/*.md",
        ".claude/commands/*.md",
        ".claude/hooks/*.py",
        ".claude/hooks/**/*.py",
        ".claude/skills/*/SKILL.md",
        "src/copilot-cli/agents/*.agent.md",
        "src/copilot-cli/hooks/*.py",
        "src/copilot-cli/hooks/**/*.py",
        "src/copilot-cli/skills/*/SKILL.md",
    ]
    FIX_HINT = (
        "Run python3 build/scripts/validate_marketplace_counts.py --fix "
        "to auto-correct."
    )


    def _import_validator(project_dir: Path):
        """Import validate_known_marketplaces, adding build/scripts to sys.path if needed."""
        try:
            from validate_marketplace_counts import validate_known_marketplaces
            return validate_known_marketplaces
        except ImportError:
            pass
        scripts_dir = project_dir / "build" / "scripts"
        if scripts_dir.is_dir() and str(scripts_dir) not in sys.path:
            sys.path.insert(0, str(scripts_dir))
        from validate_marketplace_counts import validate_known_marketplaces
        return validate_known_marketplaces


    def _validate(_matching: list[str], _all_changed: list[str]) -> list[str]:
        project_dir = Path(get_project_directory())
        try:
            validate_known_marketplaces = _import_validator(project_dir)
        except ImportError as exc:
            return [
                f"build/scripts/validate_marketplace_counts.py: import error - {exc}"
            ]

        out_buf = io.StringIO()
        err_buf = io.StringIO()
        with contextlib.redirect_stdout(out_buf), contextlib.redirect_stderr(err_buf):
            rc = validate_known_marketplaces(repo_root=project_dir)

        captured = out_buf.getvalue().splitlines()
        err_lines = [line for line in err_buf.getvalue().splitlines() if line.strip()]

        if rc == 0:
            return []

        if rc == 2:
            # Config errors land on stderr (validator's own pattern). Surface
            # them in the violation list so the agent sees the real cause
            # instead of a generic "config error" placeholder.
            detail = " ; ".join(err_lines) if err_lines else (
                captured[0] if captured else "config error"
            )
            return [f"build/scripts/validate_marketplace_counts.py: config error - {detail}"]

        violations = [line for line in captured if line.strip()]
        if err_lines:
            violations.extend(err_lines)
        violations.append(FIX_HINT)
        return violations


    def main() -> int:
        # include_deletions=True: the marketplace counter walks the live
        # filesystem regardless of which paths the diff lists, so we must
        # fire on deletion-only pushes too. The validator never reads the
        # listed paths, so deleted entries cannot trigger FileNotFoundError.
        return run_guard(_validate, GLOBS, GUARD_NAME, include_deletions=True)


    return main()

_shim_dispatch()
